    "letters": {
      "ravenpost_welcome": {
        "sender": "Havraní pošta",
        "subject": "Havrani teď létají pro tebe",
        "body": "Cestovateli,\n\nHavraní pošta otevřela svá bidla po celém údolí. Hledej havraní sloupy v Eastbrooku, Fenbridge a Highwatchi: z kteréhokoli z nich můžeš posílat dopisy, mince a zboží jiným dobrodruhům a vyzvednout vše, co ti havrani přinesou.\n\nPřikládáme malou pozornost pro tvou první známku.\n\nKřídla vzhůru,\nHavraní pošta"
      },
      "letter_q_wolves": {
        "sender": "Maršál Redbrook",
        "subject": "Ohrady jsou znovu tiché",
        "body": "Pastevci mohou pro jednou spát s oběma očima zavřenýma, a to díky tobě. Řekl jsem Havraní poště, aby ti z fondu hlídky přinesla malou odměnu.\n\nUdržuj čepel naolejovanou.\n- Maršál Redbrook"
      },
      "letter_q_greyjaw": {
        "sender": "Maršál Redbrook",
        "subject": "Starý Šedočelista, konečně",
        "body": "Zprávy se v tak malém městě šíří rychle. Pastevci včera pili na tvé zdraví a Wilkes přísahá, že ten vlk byl velký jako vůz. Ať přehánějí: zasloužil sis to.\n\nPřijď se najíst na hlídku.\n- Maršál Redbrook"
      },
      "letter_q_hollow": {
        "sender": "Bratr Aldric",
        "subject": "Tvůj čin v temnotě",
        "body": "Jen málokdo se kdy dozví, co bylo pohřbeno v té dutině, a ještě méně by tomu věřilo. Já to vím a nezapomenu.\n\nAť je tvá cesta osvětlena.\n- Bratr Aldric"
      }
    },
